// Story 7.3 AC1+AC2: extract individual listings from the OJ.ph public
// listings HTML page and run per-URL SHA-256 dedup against this flow's
// own static-data namespace (`onlinejobs_ph.seen_urls`). The namespace is
// scoped so it does not collide with the Upwork flow's dedup store.
//
// FR11: this flow MUST NOT log into OnlineJobs.ph. No session cookie is
// sent on the fetch above; only the public listings HTML is parsed here.
const crypto = require('crypto');

const html = String($json.body || '');
const nowIso = new Date().toISOString();

// Extract every job-posting link from the listings HTML. OJ.ph job-detail
// URLs follow the `/jobseekers/job/<slug-id>` pattern; the regex is kept
// deliberately permissive so the flow does not break when OJ.ph tweaks the
// surrounding markup.
const hrefRe = /href="(\/jobseekers\/job\/[A-Za-z0-9_\-]+)"/g;
const seen = new Set();
const listings = [];
let match;
while ((match = hrefRe.exec(html)) !== null) {
  const path = match[1];
  if (seen.has(path)) continue;
  seen.add(path);
  const url = 'https://www.onlinejobs.ph' + path;
  // Use the link's surrounding text window as the JD snippet. The full
  // JD body is fetched server-side downstream — n8n only forwards what
  // it can scrape from the listings page.
  const start = Math.max(0, match.index - 400);
  const end = Math.min(html.length, match.index + 800);
  const jdText = html.slice(start, end).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  listings.push({ url, jdText });
}

// Per-flow static-data dedup store. The namespace key `onlinejobs_ph`
// keeps these hashes from colliding with Story 7.2's `upwork` namespace.
const staticData = $getWorkflowStaticData('global');
if (!staticData.onlinejobs_ph) {
  staticData.onlinejobs_ph = { seen_urls: {} };
}
const seenUrls = staticData.onlinejobs_ph.seen_urls;

const out = [];
for (const item of listings) {
  const hash = crypto.createHash('sha256').update(item.url).digest('hex');
  if (seenUrls[hash]) continue; // AC2: already-seen hashes are dropped.
  out.push({
    json: {
      source: 'onlinejobs_ph',
      jd_text: item.jdText,
      url: item.url,
      discovered_at: nowIso,
      _url_hash: hash
    }
  });
}
return out;

// AC3: record the URL hash only on 2xx. Non-2xx leaves the hash absent
// from the dedup store so the next cron tick retries the same URL.
const staticData = $getWorkflowStaticData('global');
if (!staticData.onlinejobs_ph) {
  staticData.onlinejobs_ph = { seen_urls: {} };
}
const hash = $node['Extract listings + dedup'].json['_url_hash'] || $json._url_hash;
if (hash) {
  staticData.onlinejobs_ph.seen_urls[hash] = new Date().toISOString();
}
return [{ json: { recorded: Boolean(hash) } }];
